// ── Helpers ────────────────────────────────────────────────────────────────

// formatTurnLabel builds the chat-bubble header for an assistant turn.
// Format: "{agent}.{providerName}" — provider type is dropped (caller
// can still look it up in the session header); provider name is the
// part after the slash in "type/name". Default agent "main" is hidden
// so the label collapses to just the provider name in the common
// single-agent case.
func formatTurnLabel(agent, provider string) string {
	name := provider
	if i := strings.LastIndex(provider, "/"); i >= 0 {
		name = provider[i+1:]
	}
	switch {
	case agent == "" || agent == "main":
		return name
	case name == "":
		return agent
	default:
		return agent + "." + name
	}
}

// rowFallbackLifecycle maps the persisted session.Meta.Status (used
// when the pool has no live entry for a row) onto a lifecycle the
// badge renderer understands.
func rowFallbackLifecycle(status string) string {
	switch status {
	case "running":
		return "working"
	case "queued":
		return "spawning"
	}
	return "killed"
}

// relTime returns a short human-readable relative time string.
func relTime(t time.Time) string {
	if t.IsZero() {
		return "—"
	}
	d := time.Since(t)
	switch {
	case d < time.Minute:
		return "just now"
	case d < time.Hour:
		return fmt.Sprintf("%dm ago", int(d.Minutes()))
	case d < 24*time.Hour:
		return fmt.Sprintf("%dh ago", int(d.Hours()))
	default:
		return fmt.Sprintf("%dd ago", int(d.Hours()/24))
	}
}

func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}

